    // MARK: the detent — cell-crossing ticks (why big cells give precision)
    /// The cell boundaries between two lifted positions (Manhattan). Each unit is one
    /// CellTick: the drag is detented to the lattice (lawTickConservation).
    @inline(__always)
    public static func cellsCrossed(_ a: (col: Int, row: Int), _ b: (col: Int, row: Int)) -> Int {
        abs(b.col - a.col) + abs(b.row - a.row)
