    /// One clock-frame step in an n-frame loop (== Spec.PlaybackClock.frameAfter).
    @inline(__always)
    static func frameAfterN(_ n: Int, _ f: Int) -> Int {
        n <= 0 ? 0 : (f + 1) % n
