    public static let rejectInk: (r: Int, g: Int, b: Int) = (220, 60, 60)

    // MARK: reactive color + pulse (integer Q16 — the renderer samples per frame)
    public static let q16One: Int = 65536
    /// A portable integer triangle wave: periodic, bounded to [lo, hi].
    public static func pulseSampleQ16(period: Int, lo: Int, hi: Int, tick: Int) -> Int {
        let p = max(2, period)
        let phase = ((tick % p) + p) % p
        let half = p / 2
        let tri = phase <= half ? phase : p - phase
        return half == 0 ? lo : lo + (hi - lo) * tri / half
    }
    /// The live pulse from the drop verdict + drag distance: reject pulses faster &
    /// wider, farther drags pulse faster (lawReactiveFaster).
    public static func reactivePulse(identity: ColorIdentity, accept: Bool, dragMag: Int)
        -> (period: Int, lo: Int, hi: Int) {
        let basePeriod = pulseBasePeriod(identity)
        let lo = pulseBaseLo(identity)
        let baseHi = pulseBaseHi(identity)
        let urgent = accept ? 0 : basePeriod / 2
        let faster = min(basePeriod - 2, max(0, dragMag))
        let period = max(4, basePeriod - urgent - faster)
        let hi = accept ? baseHi : min(q16One, baseHi + q16One / 8)
        return (period, lo, hi)
    }
    /// Lerp a base sRGB8 toward an accent by a Q16 amplitude (the cells breathe).
    public static func tintLerpQ16(base: (r: Int, g: Int, b: Int),
                                   accent: (r: Int, g: Int, b: Int), ampQ16: Int)
        -> (r: Int, g: Int, b: Int) {
        let a = max(0, min(q16One, ampQ16))
        func mix(_ x: Int, _ y: Int) -> Int { x + (y - x) * a / q16One }
        return (mix(base.r, accent.r), mix(base.g, accent.g), mix(base.b, accent.b))
    }

